const CHIZUKIM = [{"text":"הנשמה שה׳ נתן בך היא חלק ממנו ממש — לא מטאפורה אלא מציאות רוחנית. וכשם שחלק מן השמש אינו יכול להיות חשוך לגמרי, כך הנשמה אינה יכולה לאבד את אורה לגמרי. גם בשעות הקשות ביותר, גם לאחר נפילות ארוכות — הניצוץ הפנימי שם, שמור, ממתין. מה שנדרש מן האדם אינו ליצור את האור מחדש — אלא להסיר את המחסומים שמסתירים אותו. זו עבודת כל חיי האדם: לחשוף את מה שכבר קיים בו מאז ומתמיד.","source":"תניא פרק ב — אדמו\"ר הזקן"},{"text":"אמר רבי נחמן מברסלב: אם אתה מאמין שיכולים לקלקל — תאמין שיכולים לתקן. זו אחת הסברות העמוקות ביותר שנאמרו בעולם הרוחניות. האמונה ביכולת הנפילה והאמונה ביכולת התיקון אינן סתירות — הן שתי פנים של אותה אמת. מי שמאמין שנפל לעומק, אם יפנה את אמונה זו כלפי מעלה, יגלה שהוא מאמין גם ביכולת לעלות לגובה מקביל. ויותר מכך — התיקון שאחרי הנפילה מגיע לעומקים שמי שלא נפל לא יכול להגיע אליהם.","source":"ליקוטי מוהר\"ן ח\"ב תורה קי\"ב"},{"text":"הרמח\"ל כתב כי שורש ההתרשלות הוא שהאדם אינו מרגיש את הדחיפות של החיים. הוא חי כאילו יש לו עוד זמן אינסופי, כאילו מחר הוא בטוח, כאילו מה שלא עשה היום יוכל לעשות בעוד שנה. אבל כל יום שעובר בלא כוונה אמיתית — אינו חוזר. ואין לאדם תחליף לאותו יום שעבר. לכן אמרו חז״ל: שוב יום אחד לפני מיתתך — שפירושו המעשי: חיה כל יום כאילו הוא האחרון. לא מתוך פחד, אלא מתוך הכרה עמוקה בערך האינסופי של כל רגע שניתן לך.","source":"מסילת ישרים פרק ו — הרמח\"ל"},{"text":"רבינו בחיי מבאר בחובות הלבבות שהביטחון האמיתי בה׳ אינו פסיביות ואינו עצלות. אדם הבוטח בה׳ אינו אומר: אשב ולא אעשה דבר ויבוא הכל מן השמים. הביטחון פירושו: אעשה את כל מה שביכולתי לעשות, בחריצות ובמסירות, ואת מה שאינו בידי — את התוצאה הסופית — אניח בידי ה׳ בשלמות ובאמון. האדם הבוטח הוא בדיוק זה: פעיל ורגוע בעת ובעונה אחת. עמל בכל כוחו ואינו נסחף בחרדה על מה שאינו בשליטתו.","source":"חובות הלבבות שער הביטחון — רבינו בחיי"},{"text":"השפת אמת מלמד שכל פרשה בתורה אינה רק סיפור שהיה פעם — היא מציאות חיה הקיימת בכל דור ובכל אדם. עלייתו של אברהם מאור כשדים קורית מחדש בכל אדם שקם ממקומו ויוצא אל הלא נודע בעקבות קול פנימי. כשאדם שומע בעומק נשמתו קול שאומר לו ׳לך לך׳ — עזוב את ההרגלים, עזוב את הבטוח, לך אל מה שה׳ מראה לך — עליו לחיות את הפרשה. כי התורה אינה היסטוריה. היא מפת הנשמה, והנשמה חיה אותה בכל רגע.","source":"שפת אמת פרשת לך לך — האדמו\"ר מגור"},{"text":"תפילה שבאה מן הלב פועלת עולמות, גם כשנדמה שאין מי ששומע, גם כשהתשובה מאחרת לבוא. רבי נחמן לימד שכל מילה של תפילה אמיתית עולה ומצטרפת לאחרות, ויש תפילות שמצטברות לאורך שנים ואחר כך מגיעות כולן יחד. לפעמים תפילה אחת של לב שבור היא הטיפה שמכריעה את הכף. לכן אל תזלזל בתפילתך בשל כך שנראית קטנה או חלשה. ה׳ אינו מודד לפי מספר המילים — אלא לפי עומק הלב שמאחוריהן.","source":"ליקוטי מוהר\"ן תורה ט"},{"text":"הבעל שם טוב לימד שה׳ ירד לתוך הגשמיות כדי שהגשמיות תוכל לעלות אליו. ולכן כל דבר בעולם — גם הגשמי ביותר — יש בו ניצוץ אלוקי שממתין לגילוי. כשאדם אוכל לשם שמים, כשעובד לפרנסת משפחתו מתוך כוונה, כשנח כדי שיוכל לעבוד ה׳ — הוא מעלה ניצוצות ובונה מציאות חדשה. אין מקום שאין בו עבודה, אין רגע שאינו הזדמנות להעלות ניצוץ. כל חיי האדם הם מסע של גילוי האלוקי הנסתר.","source":"כתר שם טוב — בשם הבעש\"ט"},{"text":"אורחות צדיקים מבאר שמידת האמת היא יסוד כל המידות. לא ניתן לבנות בניין של נפש על יסוד שקר — גם אם יראה מרשים בחוץ, ינחת ויתפורר מבפנים. אמת עם עצמך פירושה: לדעת את חולשותיך ולא להכחישן, לדעת את גדולתך ולא להתכחש לה, לומר מה שחושב ולא מה שרצוי. הרחוק מאמת — רחוק מעצמו. הקרוב לאמת — קרוב לה׳, כי חותמו של הקב״ה אמת.","source":"אורחות צדיקים שער האמת"},{"text":"התניא מלמד שבכל אדם מישראל יש שני כוחות מנוגדים הנמצאים בתנועה מתמדת. אין זה מלחמה שאמורה להסתיים ביום מסוים — זוהי תנועת החיים עצמה. האדם שמצפה שיגיע יום שבו לא יצטרך עוד להילחם עם יצרו — מתאכזב. אבל האדם שמבין שהמאבק עצמו הוא המציאות, ושכל ניצחון קטן נבנה ממנו — חי בשלום עם חייו. המלחמה אינה עדות לכישלון. היא עדות לכך שאתה חי.","source":"תניא פרק כז — אדמו\"ר הזקן"},{"text":"כתב הרמב\"ם שהאדם הוא תמיד בעל בחירה — בכל עת ובכל מצב. גם כשנראה שהנסיבות כובלות, גם כשההרגלים חזקים, גם כשהסביבה מושכת לכיוון אחד — עדיין שמורה בידו הבחירה לחשוב מחשבה אחרת, לומר מילה אחרת, לעשות מעשה אחד שונה. וכל בחירה אחת מובילה לבחירה אחרת. אדם שמאמין בבחירתו — חי כאדם. אדם שמוותר על בחירתו — חי כצמח.","source":"רמב\"ם הלכות תשובה פרק ה"},{"text":"אמר הרב קוק זצ\"ל שהאהבה לכנסת ישראל היא נשמת החיים של כל עבודה רוחנית. אי אפשר לאהוב את ה׳ ולשנוא את עמו. אי אפשר לדאוג לנשמה שלך ולהתעלם מנשמת חברך. האהבה האלוקית כשהיא אמיתית מתרחבת — מן הפרט אל הכלל, מן המשפחה אל העם, מן העם אל כל הבריאה. מי שלבו סגור לאחיו — לבו סגור גם לה׳, גם אם אינו מרגיש זאת.","source":"אורות הקודש — הראי\"ה קוק"},{"text":"מסופר על הבעל שם טוב שאמר: יהודי שאינו שמח אינו עובד ה׳ כראוי, גם אם עושה את כל המצוות כהלכה. כי השמחה היא לא פרי של העבודה — היא חלק מן העבודה. אדם שמקיים תורה ומצוות מתוך עצב ומשא כבד — מראה שאינו מאמין באמת בטובת ה׳ שמאחורי הציווי. אבל מי שעושה מתוך שמחה — מאמת בכל מעשה שה׳ הוא טוב, ושרצונו הוא לטובת האדם.","source":"צוואת הריב\"ש — בשם הבעש\"ט"},{"text":"כתב ר׳ צדוק הכהן מלובלין שהנפילות של האדם אינן רק מכשולים שצריך להתגבר עליהם — הן חלק מן התוכנית. כי יש ידיעות שאדם יכול לרכוש רק מתוך נפילה. יש ענווה שמגיעה רק מנגיעה בתחתית. יש אהבה לאחרים שמגיעה רק ממי שיודע מה זה להיכשל. לכן אדם שנפל ואינו יודע למה — ידע שיש שם תוכן, שיש שם שיעור שמחכה להתגלות, ושאין נפילה ללא מטרה.","source":"צדקת הצדיק — ר׳ צדוק הכהן מלובלין"},{"text":"הרב דסלר כתב שאדם שרוצה לשנות את עצמו צריך לעבוד על נקודה אחת בלבד — נקודת הבחירה שלו. לא לנסות לשנות הכל בבת אחת, כי זה מייאש ומוביל לנפילה. אלא לאתר את הנקודה שבה הבחירה שלו עדיין חופשית ולא נעשתה הרגל, ולעבוד שם. נצחון קטן בנקודת הבחירה בונה כוח. וכוח שנבנה שם מתפשט עם הזמן לאזורים נוספים. השינוי האמיתי תמיד מתחיל בנקודה אחת.","source":"מכתב מאליהו — הרב דסלר"},{"text":"הנצי\"ב מוולוז׳ין ביאר שישנן שתי מדרגות של לימוד תורה: לימוד כדי לדעת, ולימוד כדי להיות. הראשון מוסיף ידע. השני מוסיף עצמיות. כשאדם לומד תורה ושואל לא רק ׳מה כתוב?׳ אלא ׳מה זה אומר עליי?׳ — הוא מגיע לגדולה אחרת. התורה אז אינה רק אוסף הלכות אלא מראה שבה רואים את עצמך, ואת עצמך המתוקן שאמור להיות.","source":"העמק דבר — הנצי\"ב מוולוז׳ין"},{"text":"הגאון מוילנא כתב שהעיקר אינו מה שעשה האדם — אלא כמה עמל עליו. שני אנשים שעשו אותו מעשה — שכרם שונה לפי המאמץ שהכניסו. מי שמסירות הנפש שלו גדולה יותר, גם אם הגיע לאותה מקום — גדול יותר. וזה נחמה עצומה: שה׳ לא משווה אותך לאחרים. הוא משווה אותך לעצמך — לפוטנציאל שנתן בך ולמה שעשית איתו.","source":"אגרות הגר\"א — הגאון מוילנא"},{"text":"ר׳ לוי יצחק מברדיצ׳ב נהג לסנגר על כל יהודי. כשראה יהודי פשוט שעבר עברה, היה אומר: ריבונו של עולם, ראה כמה זה קשה לו לעמוד בפני יצרו, ואף על פי כן הוא מתאמץ! וכשראה יהודי שנכשל — היה אומר: ראה כמה אהבה יש לו ללב יהודי, שגם אחרי נפילה הוא מנסה לקום! זוהי ראיית הטוב — לא עיוורת, לא שוטה, אלא עמוקה. לראות בכל אדם את הניצוץ שנאבק.","source":"קדושת לוי — ר׳ לוי יצחק מברדיצ׳ב"},{"text":"המהר\"ל מפראג ביאר שישראל ורק ישראל מסוגלים לעלייה אמיתית — לא בשל עליונות אלא בשל אופי הנשמה. הנשמה היהודית היא נשמה שתמיד חותרת לשורש, שאינה מסתפקת בפני השטח, שתמיד שואלת ׳מדוע?׳ ו׳מה האמת?׳. וזו גם הסיבה שהיהודי סובל יותר — כי אדם שנשמתו חותרת לאמת, הפער בין האמת לבין המציאות כואב יותר. אבל הכאב הזה הוא גם המנוע.","source":"גבורות ה׳ — המהר\"ל מפראג"},{"text":"כתב הרב שלמה קרליבך שאין שני אנשים שמגיעים לאותו מקום באותה דרך. לכל אחד יש שביל שלו, ניגון שלו, שאלה שלו. מי שמנסה ללכת בדרכו של אחר — יכול ללמוד ממנו, אבל בסופו של דבר יצטרך למצוא את הדרך שלו בעצמו. ולכן אחד השיעורים הגדולים ביותר הוא לא להשוות. לא להשוות את עצמך לצדיקים, לא לחברים, לא לדמויות מן הספרים. אלא לעלות בדרך שה׳ הכין לך.","source":"בשם הרב שלמה קרליבך"},{"text":"הרב חיים מוולוז׳ין כתב בנפש החיים שכוחו של האדם גדול מכפי שהוא מדמה לעצמו. כל מחשבה שאדם חושב, כל מילה שאומר, כל מעשה שעושה — יוצרים מציאות ממש. יוצרים עולמות. האדם הוא שותף אמיתי בבריאה, לא צופה בה. ולכן — לאחר שמבינים זאת — כל בחירה הופכת לבעלת משקל עצום. לא כמשא אלא כגדולה.","source":"נפש החיים שער א — ר' חיים מוולוז'ין"},{"text":"ר׳ נחמן מברסלב אמר שאסור לאדם לייאש את עצמו לעולם, בשום אופן ובשום מצב שיהיה. כי אין שום ייאוש בעולם כלל. ה׳ יתברך מלא רחמים ורחמיו אינם נפסקים. ואפילו מי שנפל לתחתית — אם הוא רוצה לחזור, אם בלבו יש רצון קטן כגרגר חרדל לשוב — ה׳ אוחז בו ומחזיר אותו. הרצון הוא הכל. לא היכולת, לא ההצלחה — הרצון.","source":"ליקוטי מוהר\"ן ח\"ב תורה עח"},{"text":"בספר בלבבי משכן אבנה מבואר שהאמונה האמיתית אינה ידיעה שה׳ קיים. כל אחד יודע זאת ברמה כלשהי. האמונה האמיתית היא חיים בתוך ה׳ — תחושה מתמדת שהוא נוכח, שהוא כאן, שהוא רואה ושומע ומחכה. כשאמונה הגיעה לדרגה זו — האדם אינו יכול לחיות אחרת. כל מעשה, כל מחשבה, עוברים דרך המסנן הזה: האם אני רוצה שה׳ יראה את זה? ובמקום שזה כובל — זה משחרר.","source":"בלבבי משכן אבנה ח\"א — הרב איתן שנדרופי"},{"text":"הרב דסלר ביאר שנתינה היא מהות קיום האדם — לא מכשיר, לא אמצעי, אלא מהות. מי שחי לקחת — חי חיי ריקנות גם אם אוסף הרבה. מי שחי לתת — חי חיי מלאות גם אם יש לו מעט. כי הנתינה מחברת את האדם לשורש נשמתו, שנוצרה בצלם אלוקים — כלומר בצלם הנותן האמיתי. ולכן כל פעם שאתה נותן — אתה מי שאתה ממש.","source":"מכתב מאליהו — הרב דסלר"},{"text":"חסידות ברסלב מלמדת שה׳ רוצה את הלב. לא את הפה, לא את הידיים — אלא את הלב. ולב שלם, אפילו אם הוא פגום, אפילו אם הוא שבור, אפילו אם הוא מלא פצעים — שווה יותר בעיני ה׳ ממעשים חיצוניים מושלמים שנעשו ללא לב. ולכן אדם שאומר: אין לי כוח להתפלל, אין לי כוונה, רק לבי בוכה — כבר התפלל. כי הלב שבוכה בפני ה׳ הוא עצמו התפילה.","source":"ליקוטי עצות — שיטת ברסלב"},{"text":"ר׳ ישראל מסלנט, מייסד תנועת המוסר, כתב שכדי לשנות מידה רעה אין מספיק לדעת שהיא רעה. הידיעה אינה מספקת. צריך לחוות את הרגש ההפוך — לעורר בעצמך תחושה עמוקה של הטוב שבצד האחר. לקרוא, לשיר, לדמיין, להתפלל — עד שהרגש החיובי נמצא בך חם וחי. כי הרגל ישן מנצח ידיעה קרה. רק רגש חם מול רגל ישן — יכול לנצח.","source":"ר' ישראל מסלנט, אגרות ומאמרים"},{"text":"הרמח\"ל כתב שהזריזות אינה רק מהירות — היא ערנות. אדם זריז הוא אדם שחיושיו פתוחים, שרואה את ההזדמנות לפני שהיא עוברת, שאינו ממתין לתנאים מושלמים. כי התנאים המושלמים לא תמיד יגיעו. ויש מצוות שזמנן עובר, יש מעשי חסד שהרגע שלהם קצר, יש מילים שאם לא נאמרו עכשיו — לא יאמרו לעולם. הזריז הוא זה שרואה את הרגע ואינו מניח לו לעבור.","source":"מסילת ישרים פרק ז — הרמח\"ל"},{"text":"כתב הרב קוק שהתשובה אינה רק חזרה למצב שלפני החטא. התשובה היא עלייה גבוה יותר ממה שהיה. כי החטא עצמו, כשמביאים אותו בתשובה, הופך לקרש קפיצה. האדם שחטא ועשה תשובה שלמה — מגיע למקומות שצדיק מושלם שלא חטא לא יכול להגיע. לא כי החטא טוב — אלא כי התשובה ממנו מעמיקה את השורשים.","source":"אורות התשובה — הראי\"ה קוק"},{"text":"ר׳ נחמן לימד שעיקר השמחה של האדם צריכה לבוא ממה שהוא — לא מהישגיו, לא ממעמדו, לא ממה שיש לו. כי אלה משתנים. אבל מה שהוא — מה שה׳ ברא בו, הניצוץ הייחודי שנתן בו ובאף אחד אחר — זה נצחי. ולכן מי שמוצא שמחה בעצם היותו — יש לו שמחה שאין לה תחתית, כי אין לה על מה להישבר.","source":"ליקוטי מוהר\"ן תורה כב"},{"text":"הגר\"א מוילנא כתב שתורה הנלמדת שלא לשמה — עדיפה על פני ביטלה. אבל תורה הנלמדת לשמה — מאירה את הנשמה בדרך שאין לה תחליף. וההבדל בין השניים הוא הכוונה. לא מה שלומד — אלא מדוע לומד. אדם שיושב ולומד ושואל בלבו: ה׳, תרצה שאני מבין יותר ממך? — כבר לומד לשמה, גם אם טרם הגיע לעומק.","source":"ביאור הגר\"א — הגאון מוילנא"},{"text":"בעל ה׳ח׳ חיים כתב שכל מילה שיוצאת מפי האדם יוצאת לעולם ואינה חוזרת. לכן המילים שלנו הן כלי שצריך לשמור עליו. מילה של עידוד — מחיה נפש. מילה של כאב — יכולה לפצוע עמוק יותר ממכה גופנית. ומילה של תורה שנאמרת בציבור — יוצרת עולמות. לכן שמור על לשונך לא מפחד — אלא מהכרה בכוחה.","source":"חפץ חיים — ר' ישראל מאיר הכהן"},{"text":"המגיד ממזריץ, תלמידו של הבעש\"ט, לימד שאהבת ה׳ והיראה ממנו אינן ניגודים — הן משלימות. היראה היא הכרה בגדולתו האינסופית. האהבה היא הכרה בטובו האינסופי. מי שרק ירא — עובד מרחק. מי שרק אוהב — עלול לאבד כבוד. אבל מי שיש בו שניהם — מתקרב אליו כבן המתקרב לאב גדול: ביראה וגם בחיבה, בכבוד וגם בקרבה.","source":"מגיד דבריו ליעקב — המגיד ממזריץ"},{"text":"ר׳ שמחה בונם מפשיסחא אמר שכל אדם צריך לשאת שני פתקים: אחד בכיס ימין ובו כתוב ׳בשבילי נברא העולם׳, ואחד בכיס שמאל ובו כתוב ׳ואנכי עפר ואפר׳. והגדולה היא לדעת מתי להוציא איזה פתק. ברגע של ייאוש — ׳בשבילי נברא העולם׳, זכור שאתה יקר לאין שיעור. ברגע של גאווה — ׳ואנכי עפר ואפר׳, זכור מאין באת. שתי האמיתות יחד עושות אדם שלם.","source":"שיחות ר' שמחה בונם מפשיסחא"},{"text":"הרב כשר כתב שמצות לימוד תורה שונה מכל המצוות האחרות בנקודה אחת: אין לה שיעור עליון. כל מצווה אחרת — יש לה שיעור: כזית מצה, ארבע כוסות, ציצית. אבל תלמוד תורה — ׳והגית בו יומם ולילה׳. כל הזמן. ולכן אדם שלומד לרגע — קיים מצוה, ואדם שלמד כל ימיו — לא יצא ידי חובתו ׳לגמרי׳. כי היא מצווה ללא גבול עליון, מצווה של אינסוף.","source":"אנציקלופדיה תלמודית — הרב מאיר כשר"},{"text":"בלבבי משכן אבנה מלמד שכדי לבנות את ה׳משכן הפנימי׳ — המקדש שבלב — צריך שקט. לא שקט חיצוני בלבד, אלא שקט פנימי: להפסיק להיות מוסח, להפסיק לברוח, לשבת עם עצמך בלי ריצה. וזה קשה בעולם המודרני. אבל כשם שגשם אינו יכול להיכנס לאדמה כשהיא קשה — כך אור אלוקי אינו יכול לחדור ללב שמוסח תמיד. השקט הוא ההכנה.","source":"בלבבי משכן אבנה ח\"ב — הרב איתן שנדרופי"},{"text":"האריז\"ל גילה שיש ניצוצות קדושים גנוזים בכל מקום בעולם — בתוך הקלפות עצמן. ותפקיד האדם לשחרר אותם. כיצד? על ידי מעשים של קדושה, תפילה, לימוד, ועזרה לאחרים. כל מעשה טוב שהאדם עושה — משחרר ניצוצות ומעלה אותם. ולכן שום מעשה טוב אינו קטן מדי. גם חיוך לאדם עצוב, גם מילה טובה, גם דקה של תפילה אמיתית — מעלה עולמות.","source":"עץ חיים — האריז\"ל"},{"text":"רבינו יונה גירונדי כתב שהחרטה על העבר אינה מספקת לבדה. צריך שלושה דברים: חרטה, פרישה מן החטא, וקבלה לעתיד. אבל הסוד שגילה הוא שגם אם לא עמד בהחלטתו — התשובה עדיין פועלת. כל רגע של חרטה אמיתית, גם אם שוב נכשל — חצב בסלע. וסלע שחוצבים בו שוב ושוב — בסופו של דבר נפתח. אל תתייאש מן התהליך.","source":"שערי תשובה — רבינו יונה גירונדי"},{"text":"הסבא מסלבודקה לימד שגדלות האדם היא תנאי לקיום מצוות כראוי. אדם שמזלזל בעצמו, שאינו רואה את ערכו — לא יוכל לעבוד ה׳ כראוי. כי איך יעמוד לפני מלך מלכי המלכים אם הוא עצמו מרגיש ׳שהוא פחות מכלום׳? עמידה לפני ה׳ דורשת גאון של ידיעת הערך העצמי, גאון של ׳בשבילי נברא העולם׳ — ואז, מתוך גדלות זו, להכנע.","source":"אור הצפון — הסבא מסלבודקה"}];
function getDailyChizuk(dateStr) {
  const [y,m,d] = dateStr.split('-').map(Number);
  const dayOfYear = Math.floor((new Date(y,m-1,d) - new Date(y,0,0)) / 86400000);
  return CHIZUKIM[dayOfYear % CHIZUKIM.length];
}

// ========== HALACHOT ==========
const HALACHOT_DB = {"default": [["נטילת ידיים שחרית", "בכל יום אחר שיקום ממיטתו צריך ליטול ידיו במים בכלי, ויברך קודם הניגוב: על נטילת ידיים. נוטל ג׳ פעמים לסירוגין. מי שאין לו כלי יטול מהברז ג׳ פעמים לסירוגין, אך לא יברך על נטילת ידיים.", "ילקוט יוסף, הל׳ השכמת הבוקר סי׳ ד"], ["שכח יעלה ויבא בברכת המזון בראש חודש", "טעה ולא אמר יעלה ויבא בברכת המזון בראשי חודשים, אינו חוזר — בין ביום ובין בלילה. הטעם: מאחר ואין חיוב לאכול לחם בראש חודש, נמצא שהייתה לו האפשרות שלא לאכול לחם ולא להתחייב כלל בברכת המזון. ואם נזכר קודם שהתחיל בברכת הטוב והמטיב, אומר שם בלי שם ומלכות: ברוך שנתן ראשי חודשים לעמו ישראל לזכרון.", "ילקוט יוסף, ח׳ג דיני ברהמ׳ז וברכות עמוד שמז"], ["ברכת המזון בכל לשון", "ברכת המזון נאמרת בכל לשון שמבין, ומצוה מן המובחר לברך בלשון הקודש. כל הזהיר בברכת המזון מזונותיו מצויות לו כל ימיו בכבוד. נכון לברך היכא דאפשר מתוך הכתב ולא בעל פה.", "ילקוט יוסף, הל׳ ברכות עמוד שז"], ["שלש ברכות ברכת המזון מעכבות", "שלש הברכות הראשונות של ברכת המזון מעכבות זו את זו. לכן אם אינו יודע לברך אלא חלק מהברכות, לא יברך ברכת המזון כלל. ברכת הטוב והמטיב אינה מן התורה ואינה מעכבת.", "ילקוט יוסף, ח׳ג דיני ברהמ׳ז וברכות עמוד שיב"], ["כוונה בקריאת שמע", "צריך לדקדק ולכוון בקריאת שמע, ובפרט בפסוק ראשון: שמע ישראל. יכוון לקבל עליו עול מלכות שמים. לא יקרא בקול גבוה עד שייגע, אלא בנחת ובכוונה.", "ילקוט יוסף, סי׳ סא"], ["תפילת מנחה", "מצות חכמים להתפלל מנחה בכל יום. זמן מנחה קטנה מתשע שעות ומחצה עד השקיעה. לא יתפלל מנחה בערב שבת סמוך לשקיעה אלא יתפלל קודם. מי שלא התפלל מנחה — מתפלל ערבית פעמיים.", "ילקוט יוסף, סי׳ רלג"], ["ברכת הנהנין", "אין לאכול שום דבר לפני שיברך עליו. על לחם — המוציא. על פירות האילן — בורא פרי העץ. על פירות האדמה — בורא פרי האדמה. על שאר — שהכל נהיה בדברו. ברכה לבטלה — איסור מן התורה לדעת מרן השלחן ערוך.", "ילקוט יוסף, סי׳ ר׳ב"], ["אמירת אמן", "יענה אמן בכוונה ולא יחטוף. לא יענה אמן קודם שסיים המברך. לא יאריך יותר מדי. אמן יהא שמיה רבא — יענה בכל כוחו. העונה אמן יהא שמיה רבא בכוונה — מוחלין לו עוונותיו.", "ילקוט יוסף, סי׳ קכד"]], "shabbat": [["הדלקת נרות שבת", "מצות חכמים להדליק נרות בערב שבת. האשה מדלקת ואחר כך מברכת: להדליק נר של שבת. אחרי ברכתה קיבלה שבת ואסורה במלאכה. הבעל שהדליק בעד אשתו מברך קודם ההדלקה. מצוה להדליק לפחות שני נרות.", "ילקוט יוסף שבת כרך א, סי׳ רסג"], ["קידוש בשבת", "מצות עשה מן התורה לקדש את השבת בדיבור. אומר ויכולו ומברך בורא פרי הגפן ועל קידוש היום. שיעור כוס: רביעית. מי שאין לו יין מקדש על לחם.", "ילקוט יוסף שבת כרך א, סי׳ רסב"], ["שלש סעודות שבת", "חייב לאכול שלש סעודות בשבת: בלילה, בבוקר, ובסעודה שלישית. בכולן לחם משנה. סעודה שלישית — אחרי מנחה. מי שאינו יכול מחמת חולי פטור.", "ילקוט יוסף שבת כרך ב, סי׳ רצא"], ["מלאכות אסורות בשבת", "שלשים ותשע מלאכות אסורות בשבת מן התורה. הכותב שתי אותיות חייב. המבשל חייב. המוחק חייב. בספק מלאכה יש לשאול רב. פיקוח נפש דוחה שבת.", "ילקוט יוסף שבת כרך ב"], ["הבדלה במוצאי שבת", "מצות חכמים להבדיל על הכוס בצאת שבת. מברך בורא פרי הגפן, בורא מיני בשמים, בורא מאורי האש, המבדיל בין קדש לחול. אין לעשות מלאכה לפני הבדלה.", "ילקוט יוסף שבת כרך ב, סי׳ רצו"], ["רצה והחליצנו בברכת המזון בשבת", "בשבת אומר בברכה שלישית של ברכת המזון: רצה והחליצנו. טעה ולא אמר, ונזכר קודם שחתם בונה ירושלים, יאמר למדני חוקיך ויחזור לאמר רצה והחליצנו. נזכר אחרי שחתם, אומר בשם ומלכות: ברוך שנתן שבתות למנוחה לעמו ישראל.", "ילקוט יוסף, ח׳ג דיני ברהמ׳ז וברכות"], ["לימוד תורה בשבת", "שבת מסוגלת ללימוד תורה. מנהג ישראל לחזור על פרשת השבוע — שניים מקרא ואחד תרגום. לומד מה שלבו חפץ. עונג שבת כולל שמיעת שיעורים ועיון בספרים.", "ילקוט יוסף שבת כרך א, סי׳ ר׳פ"]], "pesach": [["בדיקת חמץ", "בודקים חמץ בליל י׳׳ד ניסן לאור הנר. המנהג להניח עשר פיסות לחם. אחרי הבדיקה מבטל: כל חמירא וחמיעא דאיכא ברשותי. אם ערב פסח חל בשבת, בודקים בליל חמישי.", "ילקוט יוסף חמץ ומצה, סי׳ תלא-תלג"], ["ביעור חמץ", "שורפים חמץ ביום י׳׳ד ניסן עד שעה חמישית. אחרי השריפה מבטלים שוב. חמץ שנמכר לגוי לפני הפסח מותר לאחריו. חמץ שעבר עליו הפסח ולא נמכר — אסור בהנאה.", "ילקוט יוסף חמץ ומצה, סי׳ תמה-תמח"], ["ארבע כוסות", "חייב לשתות ארבע כוסות בליל הסדר, גם נשים. שיעור כל כוס: רוב רביעית. מצוה מן המובחר ביין אדום. מי שנזיק לו יין שותה מיץ ענבים.", "ילקוט יוסף חמץ ומצה, סי׳ תעב"], ["אכילת מצה", "מצוה מן התורה לאכול מצה בליל ט׳׳ו ניסן. שיעור: כזית מצה שמורה. אוכל לפני חצות. מצוה מן המובחר מצה שמורה משעת קצירה.", "ילקוט יוסף חמץ ומצה, סי׳ תעה"], ["ספירת העומר בפסח", "מצוה מן התורה לספור עומר מט׳׳ז ניסן. סופר בלילה לאחר צאת הכוכבים. שכח לילה — סופר ביום ללא ברכה, וממשיך הלילה עם ברכה. שכח יום שלם — ממשיך ללא ברכה.", "ילקוט יוסף, סי׳ תפט"]], "omer": [["מצות ספירת העומר", "מצוה מן התורה לספור עומר מט׳׳ז ניסן. סופר בלילה בעמידה. שכח לספור לילה — סופר ביום ללא ברכה, וממשיך לספור בלילות הבאים עם ברכה. שכח יום שלם לגמרי — ממשיך ללא ברכה לכל שאר הימים.", "ילקוט יוסף, סי׳ תפ׳׳ט"], ["ברכת ספירת העומר", "מברך לפני הספירה: לספור את העומר. אמר מניין לפני הספירה בדרך שאלה — יש אומרים שיספור בלא ברכה. אחר שספר לא יספור שנית אם כבר יצא.", "ילקוט יוסף, סי׳ תפ׳׳ט"], ["אבלות ספירת העומר", "נוהגים שלא להסתפר בימי הספירה ושלא לערוך חתונות. לספרדים ועדות המזרח — מותר מיום ל׳׳ג בעומר ואילך. בל׳׳ג בעומר עצמו מותר לכולם.", "ילקוט יוסף, הלכות מועדים"], ["ל׳׳ג בעומר", "ל׳׳ג בעומר הוא יום פטירת רבי שמעון בר יוחאי. ביום זה מותר להסתפר ולערוך חתונות לכולם. מדליקים מדורות לכבודו.", "ילקוט יוסף, הלכות מועדים"]], "shavuot": [["תיקון ליל שבועות", "מנהג ישראל להישאר ערים כל ליל שבועות ולעסוק בתורה. מי שנשאר ערה כל הלילה, בבוקר יטול ידיו בלא ברכה. לכתחילה ישן מעט לפני צאת הכוכבים כדי שיוכל לקרוא קריאת שמע על המיטה.", "ילקוט יוסף, הלכות מועדים, סי׳ תצ׳׳ד"], ["מאכלי חלב בשבועות", "מנהג ישראל לאכול מאכלי חלב בשבועות. אוכלים תחילה סעודה חלבית, מפסיקים, מדיחים ומקנחים את הפה, ואוכלים סעודה בשרית. גבינה קשה שחלפו עליה ו׳ חודשים — צריך ו׳ שעות המתנה לפני בשר.", "ילקוט יוסף, הלכות מועדים"], ["קבלת התורה", "שבועות — חג מתן תורתנו. ״נעשה ונשמע״ — ישראל קיבלו התורה בשמחה. מצוה לשמוח בחג ולאכול ולשתות. לימוד תורה ביום זה — מצוה גדולה במיוחד.", "ילקוט יוסף, הלכות מועדים"]], "roshHashana": [["תקיעת שופר", "מצוה מן התורה לשמוע קול שופר בראש השנה. מאה קולות: שלשים תשר׳׳ת, שלשים תש׳׳ת, שלשים תר׳׳ת. לא ידבר בין ברכת השמיעה לתקיעות. שופר כשר — קרן איל, אינה פגומה.", "ילקוט יוסף מועדים, סי׳ תקפה"], ["סימנים בראש השנה", "נוהגים לאכול סימנים בראש השנה: תפוח בדבש — שנה מתוקה, רימון — נרבה זכויות, ראש כבש — נהיה לראש. אומר: יהי רצון מלפניך שתחדש עלינו שנה טובה ומתוקה.", "ילקוט יוסף מועדים, סי׳ תקפג"], ["תפילת מוסף בראש השנה", "מוסף ראש השנה כולל מלכויות — קבלת עול מלכות שמים, זכרונות — ה׳ זוכר הכל, שופרות — מתן תורה ועתיד לבוא. תוקעים בין כל קטע. זכרנו לחיים מלך חפץ בחיים.", "ילקוט יוסף מועדים, סי׳ תקפב"]], "yomKippur": [["חמשה עינויים", "חמישה עינויים ביום כיפור: אכילה ושתייה, רחיצה, סיכה, נעילת הסנדל ותשמיש המיטה. קטן מתחת לגיל תשע — אין מענים. מגיל תשע עד בר מצוה — מחנכים בשעות. חולה שיש בו סכנה — פוסק רב.", "ילקוט יוסף מועדים, סי׳ תריב"], ["וידוי ביום כיפור", "מצוה להתוודות ביום כיפור. אשמנו, בגדנו, גזלנו — כ׳׳ב חטאים כנגד כ׳׳ב אותיות. לוחה על חזהו בשעת הוידוי. יום כיפור מכפר על עברות בין אדם למקום. על עברות בין אדם לחברו — אין יום כיפור מכפר עד שיפייסו.", "ילקוט יוסף מועדים, סי׳ תרו"], ["תפילת ניעילה", "תפילת ניעילה היא אחרונה ביום כיפור. מתפלל בכוונה עצומה. גומר בשמע ישראל פעם אחת, ברוך שם שבע פעמים, ה׳ הוא האלוקים שבע פעמים. תקיעה אחת גדולה.", "ילקוט יוסף מועדים, סי׳ תרכ"]], "sukkot": [["מצות ישיבה בסוכה", "מצוה מן התורה לישב בסוכה שבעה ימים — כעין תדורו. ישן, אוכל ושותה בסוכה. ירדו גשמים שנכנסים לסוכה — פטור. מצטער פטור. ברכה: לישב בסוכה — בפעם הראשונה שנכנס לאכול.", "ילקוט יוסף מועדים, סי׳ תרלט"], ["ארבעת המינים", "מצוה מן התורה ליטול ארבעת המינים ביום הראשון. לולב, שלשה הדסים, שתי ערבות ואתרוג. מנענע: מזרח, דרום, מערב, צפון, מעלה, מטה. אתרוג כשר: אינו מורכב, אינו חסר.", "ילקוט יוסף מועדים, סי׳ תרמה"], ["הושענות ושמיני עצרת", "מקיפים את הבימה עם לולב בכל יום ואומרים הושענות. בהושענא רבה — שבע הקפות ומכים ערבה. שמיני עצרת — רגל בפני עצמו, אומרים משיב הרוח, מתפללים גשם.", "ילקוט יוסף מועדים"]], "chanukah": [["הדלקת נר חנוכה", "מדליק בפתח הבית מבחוץ, או בחלון. מוסיף נר בכל לילה — משמאל לימין. מדליק לאחר צאת הכוכבים. מברך: להדליק נר חנוכה, שעשה ניסים. בלילה הראשון מוסיף שהחיינו.", "ילקוט יוסף מועדים, סי׳ תרעב"], ["שיעור שמן בנר חנוכה", "שיעור שמן — שידלק חצי שעה לאחר צאת הכוכבים. אם כבה לפני כן, אינו מדליק שנית אם לא היה שמן מספיק. מצוה מן המובחר שמן זית. אסור להשתמש לאורן.", "ילקוט יוסף מועדים, סי׳ תרעג"], ["הלל בחנוכה", "גומרים הלל כל שמונת ימי חנוכה. אל הניסים אומרים בתפילה ובברכת המזון. חנוכה שחל בשבת — מדליק חנוכה ואחר כך שבת. מוצאי שבת — מבדיל ואחר כך מדליק.", "ילקוט יוסף מועדים, סי׳ תרפג"]], "purim": [["קריאת מגילת אסתר", "מצוה לשמוע מגילת אסתר בלילה וביום. שמיעה כקריאה. פספס מילה — חוזר. שמות עשרת בני המן — בנשימה אחת. לא ידבר בשעת הקריאה.", "ילקוט יוסף מועדים, סי׳ תרצ"], ["ארבע מצוות פורים", "מקרא מגילה, משלוח מנות — שתי מנות לאיש אחד, מתנות לאביונים — שתי מתנות לשני עניים, סעודת פורים ביום. שמחה ביום פורים — מצוה.", "ילקוט יוסף מועדים, סי׳ תרצה"], ["משלוח מנות", "משלוח מנות: שתי מנות מוכנות לאכילה לאיש אחד לפחות. אשה שולחת לאשה. מצוה עדיפה על ידי שליח. הנוהגים לשלוח לרבים — משובח.", "ילקוט יוסף מועדים, סי׳ תרצה"]], "cholHamoed": [["מלאכה בחול המועד", "מלאכה בחול המועד אסורה מדרבנן, פרט לצורך המועד. מותר לבשל ולרחוץ לצורך המועד. אסור לכבס, לתפור, לכתוב שלא לצורך — אם היה יכול לעשות לפני המועד.", "ילקוט יוסף מועדים, סי׳ תל"], ["שמחת המועד", "מצוה לשמוח בחג — ושמחת בחגך. קונה מתנות לאשתו ולילדיו. מטייל ונהנה. אין מתאבלים בחול המועד ואין נוהגים אבלות בפרהסיא.", "ילקוט יוסף מועדים, סי׳ תקכט"], ["יעלה ויבא בחול המועד", "שכח יעלה ויבא בתפילה בחול המועד — חוזר. שכח בברכת המזון: בלילה הראשון של פסח — חוזר. בשאר ימי חול המועד — אינו חוזר.", "ילקוט יוסף מועדים, סי׳ תכב"]], "roshChodesh": [["יעלה ויבא בתפילה בראש חודש", "שכח יעלה ויבא בשחרית ונזכר לפני שעקר רגליו — חוזר לרצה. נזכר אחרי שעקר רגליו — חוזר לראש. שכח במנחה — אינו חוזר.", "ילקוט יוסף, הל׳ תפילה"], ["יעלה ויבא בברכת המזון בראש חודש", "שכח יעלה ויבא בברכת המזון בראש חודש — אינו חוזר. הטעם: אין חיוב לאכול לחם בראש חודש, ונמצא שהייתה לו האפשרות שלא לאכול לחם ולא להתחייב כלל בברכת המזון. אם נזכר קודם ברכת הטוב והמטיב — אומר בלא שם ומלכות: ברוך שנתן ראשי חודשים לעמו ישראל לזכרון.", "ילקוט יוסף, ח׳ג דיני ברהמ׳ז סי׳ קפח"]]};

