// ========== NOAA Solar Engine ==========
function toRad(d){return d*Math.PI/180;}function toDeg(r){return r*180/Math.PI;}
function dateToJD(date){const y=date.getUTCFullYear(),m=date.getUTCMonth()+1,d=date.getUTCDate();const A=Math.floor(y/100),B=2-A+Math.floor(A/4);return Math.floor(365.25*(y+4716))+Math.floor(30.6001*(m+1))+d+B-1524.5;}
function jC(jd){return(jd-2451545)/36525;}
function gLong(t){return(280.46646+t*(36000.76983+t*0.0003032))%360;}
function gAnom(t){return 357.52911+t*(35999.05029-0.0001537*t);}
function eccE(t){return 0.016708634-t*(0.000042037+0.0000001267*t);}
function eqC(t){const m=toRad(gAnom(t));return Math.sin(m)*(1.914602-t*(0.004817+0.000014*t))+Math.sin(2*m)*(0.019993-0.000101*t)+Math.sin(3*m)*0.000289;}
function oblC(t){const e0=23+(26+(21.448-t*(46.815+t*(0.00059-t*0.001813)))/60)/60;return e0+0.00256*Math.cos(toRad(125.04-1934.136*t));}
function sDecl(t){const e=toRad(oblC(t)),lam=toRad(gLong(t)+eqC(t)-0.00569-0.00478*Math.sin(toRad(125.04-1934.136*t)));return toDeg(Math.asin(Math.sin(e)*Math.sin(lam)));}
function eqT(t){const e2=eccE(t),eps=toRad(oblC(t)),l0=toRad(gLong(t)),m=toRad(gAnom(t));let y=Math.tan(eps/2);y*=y;return toDeg(y*Math.sin(2*l0)-2*e2*Math.sin(m)+4*e2*y*Math.sin(m)*Math.cos(2*l0)-0.5*y*y*Math.sin(4*l0)-1.25*e2*e2*Math.sin(2*m))*4;}
function sunUTC(date,lat,lng,ang,rise){const jd=dateToJD(date),t=jC(jd);const eot=eqT(t),decl=toRad(sDecl(t)),latR=toRad(lat);const c=(Math.sin(toRad(ang))-Math.sin(latR)*Math.sin(decl))/(Math.cos(latR)*Math.cos(decl));if(c>1||c<-1)return null;const ha=toDeg(Math.acos(c));const noon=720-4*lng-eot;return rise?noon-ha*4:noon+ha*4;}
function toLocal(date,u){if(u==null)return null;const d=new Date(Date.UTC(date.getUTCFullYear(),date.getUTCMonth(),date.getUTCDate()));d.setUTCMinutes(d.getUTCMinutes()+Math.round(u));return d;}
function fmt(d){if(!d)return'--:--';return d.toLocaleTimeString('he-IL',{timeZone:'Asia/Jerusalem',hour:'2-digit',minute:'2-digit',hour12:false});}
function addMins(d,m){return d?new Date(d.getTime()+m*60000):null;}
const LAT=32.0853,LNG=34.7818;
function getZemanim(date){
  const sr=toLocal(date,sunUTC(date,LAT,LNG,-0.833,true)),ss=toLocal(date,sunUTC(date,LAT,LNG,-0.833,false));
  const al=toLocal(date,sunUTC(date,LAT,LNG,-16.0,true)),ta=toLocal(date,sunUTC(date,LAT,LNG,-11.5,true));
  const tz=toLocal(date,sunUTC(date,LAT,LNG,-4.5,false)),rb=addMins(ss,72);
  return{date:date.toISOString().slice(0,10),sunrise:sr,sunset:ss,alot:al,talit:ta,tzet:tz,rabenu:rb,candles:addMins(ss,-20),havdalah:addMins(tz,10)};
}

