const OMER_STARTS=[new Date('2026-04-03'),new Date('2027-04-23'),new Date('2028-04-12')];
const ON=['','אחד','שניים','שלשה','ארבעה','חמישה','ששה','שבעה','שמונה','תשעה','עשרה','אחד עשר','שנים עשר','שלשה עשר','ארבעה עשר','חמישה עשר','ששה עשר','שבעה עשר','שמונה עשר','תשעה עשר','עשרים','עשרים ואחד','עשרים ושניים','עשרים ושלשה','עשרים וארבעה','עשרים וחמישה','עשרים וששה','עשרים ושבעה','עשרים ושמונה','עשרים ותשעה','שלשים','שלשים ואחד','שלשים ושניים','שלשים ושלשה','שלשים וארבעה','שלשים וחמישה','שלשים וששה','שלשים ושבעה','שלשים ושמונה','שלשים ותשעה','ארבעים','ארבעים ואחד','ארבעים ושניים','ארבעים ושלשה','ארבעים וארבעה','ארבעים וחמישה','ארבעים וששה','ארבעים ושבעה','ארבעים ושמונה','ארבעים ותשעה'];
const OW=['','שבוע אחד','שני שבועות','שלשה שבועות','ארבעה שבועות','חמישה שבועות','ששה שבועות','שבעה שבועות'];
const OD=['','יום אחד','שני ימים','שלשה ימים','ארבעה ימים','חמישה ימים','ששה ימים'];
function getOmerDay(ds){const d=new Date(ds+'T12:00:00');for(const s of OMER_STARTS){const diff=Math.round((d-s)/86400000);if(diff>=0&&diff<49)return diff+1;}return null;}
function omerText(day){const w=Math.floor(day/7),r=day%7;let s='היום '+ON[day]+' יום';if(w>0&&r>0)s+=', ש'+OW[w]+' ו'+OD[r];else if(w>0)s+=', ש'+OW[w];return s+' לעומר';}

// ========== סיווג ימים ==========
function isYomTov(ds){return(EVENTS[ds]||[]).some(e=>e.t==='chag');}
function tomorrowStr(ds){const d=new Date(ds+'T12:00:00');d.setDate(d.getDate()+1);return d.toISOString().slice(0,10);}
function isErevYomTov(ds){return isYomTov(tomorrowStr(ds));}
function getDayType(ds){
  const dow=new Date(ds+'T12:00:00').getDay();
  const evs=EVENTS[ds]||[];const names=evs.map(e=>e.n);
  const omer=getOmerDay(ds);
  if(names.some(n=>n.includes('פסח')))return'pesach';
  if(omer&&omer>0)return'omer';
  if(names.some(n=>n.includes('שבועות')))return'shavuot';
  if(names.some(n=>n.includes('ראש השנה')))return'roshHashana';
  if(names.some(n=>n.includes('כפור')||n.includes('כיפור')))return'yomKippur';
  if(names.some(n=>n.includes('סוכות')||n.includes('שמיני עצרת')))return'sukkot';
  if(names.some(n=>n.includes('חנוכה')))return'chanukah';
  if(names.some(n=>n.includes('פורים')))return'purim';
  if(evs.some(e=>e.t==='chol'))return'cholHamoed';
  if(dow===6)return'shabbat';
  return'default';
}

// ========== הלכות ללא חזרות ==========
function getHalachot(ds){
  const dayType=getDayType(ds);
  const primary=HALACHOT_DB[dayType]||[];
  const fallback=HALACHOT_DB.default||[];
  const pool=[...primary,...fallback.filter(h=>!primary.some(p=>p[0]===h[0]))];
  const seed=parseInt(ds.replace(/-/g,''))%997;
  const picked=[];const used=new Set();
  for(let i=0;i<pool.length&&picked.length<3;i++){
    const idx=(seed*7+i*13)%pool.length;
    if(!used.has(idx)){used.add(idx);picked.push(pool[idx]);}
  }
  return picked;
}

// ========== חג שנבחר — מידע מפורט ==========
function getChagKey(ds){
  const names=(EVENTS[ds]||[]).map(e=>e.n);
  if(names.some(n=>n.includes('פסח')))return'pesach';
  if(names.some(n=>n.includes('שבועות')))return'shavuot';
  if(names.some(n=>n.includes('ראש השנה')))return'roshHashana';
  if(names.some(n=>n.includes('כיפור')))return'yomKippur';
  if(names.some(n=>n.includes('סוכות')||n.includes('הושענ')||n.includes('שמיני')))return'sukkot';
  if(names.some(n=>n.includes('חנוכה')))return'chanukah';
  if(names.some(n=>n.includes('פורים')))return'purim';
  return null;
}

const TYPE_COLOR={chag:'#d4a843',chol:'#8b9e4a',fast:'#a05060',rc:'#5b8abf',modern:'#7b9eaf',spec:'#9b7ecf',minor:'#6a8080'};
const TYPE_ICON={chag:'✡️',chol:'🕍',fast:'✋',rc:'🌑',modern:'🇮🇱',spec:'✨',minor:'🔹'};
const TYPE_LABEL={chag:'חג',chol:'חוה"מ',fast:'צום',rc:'ר"ח',modern:'לאומי',spec:'שב׳ מיוחדת',minor:'מועד'};
const HW=['ראשון','שני','שלישי','רביעי','חמישי','שישי','שבת'];
const HM=['ינואר','פברואר','מרץ','אפריל','מאי','יוני','יולי','אוגוסט','ספטמבר','אוקטובר','נובמבר','דצמבר'];
const DOW=s=>new Date(s+'T12:00:00').getDay();

// ========== ערכות עיצוב ==========
const THEMES={
  dark:{bg:'#0c1015',card:'#13191f',border:'#252d36',text:'#dde4ed',muted:'#7a8795',gold:'#c9a227',goldL:'#e8c96a',blue:'#4a9eff',dawn:'#e07040',dusk:'#8f6abf',hBtn:'#1a2530',hBtnBorder:'#2a3a4a',hText:'#7bc8e0',green:'#6abf40',greenBg:'rgba(60,100,40,0.15)',greenBorder:'#3a5a2a',greenText:'#d0f0b0',greenSrc:'#6a9a50'},
  light:{bg:'#f7f3eb',card:'#fffdf7',border:'#d4c9a8',text:'#2a1f0f',muted:'#7a6a50',gold:'#8a6010',goldL:'#c09030',blue:'#1a5a9a',dawn:'#c05020',dusk:'#6a408f',hBtn:'#e8dfc8',hBtnBorder:'#c4a870',hText:'#2a5a7a',green:'#3a7020',greenBg:'rgba(180,220,150,0.2)',greenBorder:'#90c060',greenText:'#1a4010',greenSrc:'#5a8030'},
};

// ========== Components ==========
